        const updatedTeams = (settings.teams || []).map(t => t.vertical === oldName ? { ...t, vertical: trimmed } : t);
        setSettings(prev => ({ ...prev, verticals: updatedVerticals, users: updatedUsers, teams: updatedTeams }));
        setEditingId(null);
